class Solution {
public:
    int makeTheIntegerZero(int num1, int num2) {
        if (num2 >= 0) {
            if (num1 % num2 == 0) {
                return num1 / num2;
            } else {
                return -1;
            }
        } else {
            int operations = 0;
            while (num1 > 0) {
                if (num1 < 60) {
                    if (num1 >= abs(num2)) {
                        return operations + 1;
                    } else {
                        return -1;
                    }
                }
                num1 -= (1 << min(num1.bit_length() - 1, 60)) + num2;
                operations++;
            }
            return operations;
        }
    }
};
